+	}
+
+	if r.Method != "POST" {
+		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
+		return
+	}
+
+	if s.insightWorker == nil {
+		json.NewEncoder(w).Encode(InsightEnrichmentResponse{
