+// CallOpsTool calls a kubestellar-ops tool
+func (h *MCPHandlers) CallOpsTool(c *fiber.Ctx) error {
+	if h.bridge == nil {
+		return c.Status(503).JSON(fiber.Map{"error": "MCP bridge not available"})
+	}
+
