+		// Check for host network
+		if pod.Spec.HostNetwork {
+			issues = append(issues, SecurityIssue{
+				Name:      pod.Name,
+				Namespace: pod.Namespace,
+				Cluster:   contextName,
+				Issue:     "Host network enabled",
