+			ingressClass = *ing.Spec.IngressClassName
+		}
+		result = append(result, Ingress{
+			Name:      ing.Name,
+			Namespace: ing.Namespace,
+			Cluster:   contextName,
+			Class:     ingressClass,
+			Hosts:     hosts,
+			Address:   address,
+			Age:       formatAge(ing.CreationTimestamp.Time),
+			Labels:    ing.Labels,
+		})
+	}
+
+	return result, nil
+}
