+		}
+
+		result = append(result, ResourceQuota{
+			Name:        quota.Name,
+			Namespace:   quota.Namespace,
+			Cluster:     contextName,
+			Hard:        hard,
+			Used:        used,
+			Age:         age,
+			Labels:      quota.Labels,
+			Annotations: quota.Annotations,
